const MAX_UPGRADES_PER_WINDOW = 5;
const WINDOW_HOURS = 6;

const staticData = $getWorkflowStaticData('global');
const now = Date.now();
const windowMs = WINDOW_HOURS * 60 * 60 * 1000;

if (!staticData.windowStart || (now - staticData.windowStart) > windowMs) {
  staticData.windowStart = now;
  staticData.count = 0;
}

if (staticData.count >= MAX_UPGRADES_PER_WINDOW) {
  console.log('Rate limit reached: ' + staticData.count + '/' + MAX_UPGRADES_PER_WINDOW);
  return [];
}

const image = $input.first().json.body.diun_entry_image || '';
const tag = $input.first().json.body.diun_entry_imagetag || '';

const dbPatterns = ['postgres', 'mysql', 'redis', 'clickhouse', 'etcd'];
if (dbPatterns.some(p => image.toLowerCase().includes(p))) return [];

const skipPrefixes = ['viktorbarzin/', 'registry.viktorbarzin.me/', 'ancamilea/', 'mghee/'];
if (skipPrefixes.some(p => image.startsWith(p))) return [];

const infraPrefixes = ['registry.k8s.io/', 'quay.io/tigera/', 'quay.io/metallb/', 'nvcr.io/', 'reg.kyverno.io/'];
if (infraPrefixes.some(p => image.startsWith(p))) return [];

if (tag === 'latest' || tag === '') return [];

staticData.count += 1;
console.log('Upgrade ' + staticData.count + '/' + MAX_UPGRADES_PER_WINDOW + ': ' + image + ':' + tag);

return [$input.first()];
